import{c as t,S as d,j as o,m as a}from"./chunks/framework.DvQr6YbT.js";const b=JSON.parse('{"title":"核心概念","description":"","frontmatter":{},"headers":[],"relativePath":"zh/concepts/index.md","filePath":"zh/concepts/index.md","lastUpdated":1783497907000}'),r={name:"zh/concepts/index.md"};function c(l,e,i,s,n,h){return d(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to “核心概念”">​</a></h1><p>理解 Knowlery 最容易的方式，是把它看作 vault 上的一层 review surface。你的笔记是原始材料。Skills 是可复用的 prompt。Rules 是约束。Dashboard 会把最近活动整理成一组小动作，而更深的维护工具放在 Obsidian settings 中。</p><h2 id="一个核心-三个外壳" tabindex="-1">一个核心，三个外壳 <a class="header-anchor" href="#一个核心-三个外壳" aria-label="Permalink to “一个核心，三个外壳”">​</a></h2><p>同一套知识库生命周期能力提供三个外壳，共享同一种 workspace 格式：</p><table tabindex="0"><thead><tr><th>外壳</th><th>提供</th><th>安装</th></tr></thead><tbody><tr><td>Obsidian 插件</td><td>全部能力：review space、Knowledge health 界面、应用内实时检索，以及所有生命周期操作</td><td>社区插件市场</td></tr><tr><td><code>knowlery</code> CLI</td><td>完整生命周期——<code>init</code> / <code>sync</code> / <code>health</code> / <code>query</code> / <code>stale</code> / <code>kb</code> / <code>bundle …</code>——面向终端、agent 和无头环境</td><td><code>npm i -g knowlery</code></td></tr><tr><td>MCP 服务器</td><td><code>knowlery mcp</code>（stdio）与 <code>knowlery mcp serve</code>（远程 HTTP）：为任何支持 MCP 的 agent 提供工具、技能提示词和页面资源</td><td>随 CLI 附带</td></tr></tbody></table><p>CLI 初始化的文件夹用 Obsidian 打开零迁移，任何 Knowlery vault 也可以直接被 CLI 操作。所有外壳共享同一份 sync 与迁移实现，workspace 会记录最后同步它的 Knowlery 版本——旧外壳会拒绝同步，而不是把新外壳升级过的内容降级回去。MCP 能力详见 <a href="./../guides/agents-mcp">Agent 与 MCP</a>。</p><h2 id="review-space" tabindex="-1">Review Space <a class="header-anchor" href="#review-space" aria-label="Permalink to “Review Space”">​</a></h2><p>Knowlery 不会取代你的个人笔记。它会在自由笔记和 agent 维护内容之间保留边界。</p><p>Dashboard 是一个行动优先的首页：</p><table tabindex="0"><thead><tr><th>区块</th><th>用途</th></tr></thead><tbody><tr><td>Today&#39;s move</td><td>从当前活动上下文开始，选择下一步</td></tr><tr><td>Suggested moves</td><td>不必浏览原始 skill 文件，也能选择可复用 review prompt</td></tr><tr><td>Knowledge health</td><td>查看来源已变更的编译页面和从未编译的笔记，可一键复制 re-cook prompt</td></tr><tr><td>This note</td><td>review 当前 Markdown 笔记</td></tr><tr><td>Recent activity</td><td>查看最近的私有 activity receipts</td></tr><tr><td>This week</td><td>生成和 review weekly summary</td></tr><tr><td>Bundles</td><td>分享 review 过的 knowledge bundles，并管理已安装的 bundles</td></tr></tbody></table><p>Diagnostics、rules、schema shortcuts、平台切换和 Skills library 位于 <strong>Settings -&gt; Knowlery</strong>。</p><h2 id="编译后的知识层" tabindex="-1">编译后的知识层 <a class="header-anchor" href="#编译后的知识层" aria-label="Permalink to “编译后的知识层”">​</a></h2><p>Setup wizard 会创建四个顶层知识目录：</p><table tabindex="0"><thead><tr><th>目录</th><th>类型</th><th>用途</th></tr></thead><tbody><tr><td><code>entities/</code></td><td><code>entity</code></td><td>人、工具、组织、项目、产品、系统</td></tr><tr><td><code>concepts/</code></td><td><code>concept</code></td><td>想法、框架、理论、心智模型</td></tr><tr><td><code>comparisons/</code></td><td><code>comparison</code></td><td>相关对象之间的并排分析</td></tr><tr><td><code>queries/</code></td><td><code>query</code></td><td>保存的问题、调查和研究线索</td></tr></tbody></table><p>这些页面既应该方便人阅读，也应该方便 agent 稳定处理。具体结构由 <code>SCHEMA.md</code> 指导，但 Health 只会检查最小 frontmatter 核心。</p><h2 id="knowledge-md" tabindex="-1"><code>KNOWLEDGE.md</code> <a class="header-anchor" href="#knowledge-md" aria-label="Permalink to “KNOWLEDGE.md”">​</a></h2><p><code>KNOWLEDGE.md</code> 是 vault 的操作指南。它说明：</p><ul><li>哪些目录属于 agent 工作区。</li><li>哪些目录属于用户自由笔记。</li><li>Agent 应该如何检索知识。</li><li>当前有哪些 skills。</li><li>如何用 wikilinks 引用 vault 来源。</li></ul><p>Agent 在进入这个 vault 工作时，应该尽早阅读它。</p><h2 id="schema-md" tabindex="-1"><code>SCHEMA.md</code> <a class="header-anchor" href="#schema-md" aria-label="Permalink to “SCHEMA.md”">​</a></h2><p><code>SCHEMA.md</code> 是知识层的活文档，不只是 frontmatter 模板。</p><p>当前模板把内容分成这些部分：</p><ul><li>Knowledge Domains</li><li>Tag Taxonomy</li><li>Domain Taxonomy</li><li>Agent Page Conventions</li><li>Frontmatter Schema</li><li>Page Thresholds</li><li>Custom Fields</li></ul><p>模板会鼓励使用 <code>title</code>、<code>date</code>、<code>created</code>、<code>updated</code>、<code>type</code>、<code>tags</code>、<code>sources</code> 等字段，并允许 <code>status</code>、<code>domain</code>、<code>description</code>、<code>references</code>、<code>author</code> 这类可选字段。</p><p>Health diagnostics 仍然只检查知识页面的最小必需字段：</p><table tabindex="0"><thead><tr><th>类型</th><th>最小字段</th></tr></thead><tbody><tr><td>Entity</td><td><code>type</code>、<code>created</code></td></tr><tr><td>Concept</td><td><code>type</code>、<code>created</code></td></tr><tr><td>Comparison</td><td><code>type</code>、<code>items</code>、<code>created</code></td></tr><tr><td>Query</td><td><code>type</code>、<code>status</code>、<code>created</code></td></tr></tbody></table><h2 id="index-base" tabindex="-1"><code>INDEX.base</code> <a class="header-anchor" href="#index-base" aria-label="Permalink to “INDEX.base”">​</a></h2><p><code>INDEX.base</code> 是覆盖 compiled knowledge layer 的 Obsidian Bases 索引。</p><p>它面向在 Obsidian 中浏览的人，对知识页面进行分组、排序并展示有用属性。Agent 仍可按需通过 <code>obsidian base:query</code> 查询它，但为问题定位候选页面的工作由下面的确定性检索引擎完成。</p><h2 id="确定性检索" tabindex="-1">确定性检索 <a class="header-anchor" href="#确定性检索" aria-label="Permalink to “确定性检索”">​</a></h2><p>从 0.6.0 起，为问题定位候选页面是一条确定性命令，两个通道运行同一个引擎：</p><table tabindex="0"><thead><tr><th>通道</th><th>场景</th><th>命令</th></tr></thead><tbody><tr><td>应用内 CLI</td><td>Obsidian 运行中（1.12.2+，已启用 CLI）</td><td><code>obsidian knowlery:query question=&quot;...&quot; [k=&lt;n&gt;] [json]</code></td></tr><tr><td>无头脚本</td><td>Obsidian 关闭，仅需 Node</td><td><code>node .knowlery/bin/query.mjs &quot;...&quot; [--k &lt;n&gt;] [--json]</code></td></tr></tbody></table><p>引擎会扫描编译页面、用户笔记和已安装的 bundles；按字段权重评分（标题/别名 &gt; 标签 &gt; 描述 &gt; 正文）；匹配轻量词形变体和中文短语；当页面引用的原始笔记命中问题时，把分数传导给编译页面（跨语言提问也能找到编译后的答案）；没有可信匹配时返回明确的 <code>No confident matches</code>，而不是一堆噪音。</p><p>同一套机制还负责机械性的过期检测：</p><ul><li><code>obsidian knowlery:stale</code> 或 <code>node .knowlery/bin/query.mjs --stale</code> 会列出引用来源在页面写入后发生变更的编译页面、未被任何编译页面引用的用户笔记，以及指向已不存在笔记的 <code>sources</code> 引用。</li><li>Dashboard 的 Knowledge health 区块展示同一份报告，<code>/cook</code> 的增量模式以它为范围（<code>log.md</code> 仅保留为追加式历史）。</li></ul><p>检索质量是可度量的：仓库内置评测基建（<code>evals/</code>），包含 golden 问题集、旧检索流程的冻结基线，CI 会在每个 pull request 上校验分数不回退。</p><h2 id="skills-和-suggested-moves" tabindex="-1">Skills 和 Suggested Moves <a class="header-anchor" href="#skills-和-suggested-moves" aria-label="Permalink to “Skills 和 Suggested Moves”">​</a></h2><p>Skills 是安装在 <code>.agents/skills/&lt;name&gt;/SKILL.md</code> 的 markdown prompt packages。</p><p>Knowlery 当前内置这些 skills：</p><table tabindex="0"><thead><tr><th>Skill</th><th>用途</th></tr></thead><tbody><tr><td><code>cook</code></td><td>将笔记整理成知识页面并同步 <code>SCHEMA.md</code> taxonomy</td></tr><tr><td><code>ask</code></td><td>基于 vault 内容回答问题</td></tr><tr><td><code>explore</code></td><td>追踪时间线并发现连接</td></tr><tr><td><code>challenge</code></td><td>压力测试信念并检测 drift</td></tr><tr><td><code>ideas</code></td><td>从 vault 内容生成可行动想法</td></tr><tr><td><code>audit</code></td><td>扫描 agent 维护目录中的结构健康问题</td></tr><tr><td><code>organize</code></td><td>建议 vault 结构调整</td></tr><tr><td><code>obsidian-cli</code></td><td>使用 Obsidian CLI patterns</td></tr><tr><td><code>obsidian-markdown</code></td><td>编写 Obsidian-flavored markdown</td></tr><tr><td><code>obsidian-bases</code></td><td>处理 Obsidian Bases 文件</td></tr><tr><td><code>json-canvas</code></td><td>创建和编辑 JSON Canvas</td></tr><tr><td><code>defuddle</code></td><td>从网页中提取干净 markdown</td></tr><tr><td><code>vault-conventions</code></td><td>记录并执行 vault 命名约定</td></tr></tbody></table><p>Dashboard 会优先展示自然语言 moves；Settings tab 中的 Skills library 会展示背后的 source skills，并提供创建、浏览、编辑、禁用或删除能力。</p><h2 id="activity-ledger-和-weekly-summary" tabindex="-1">Activity Ledger 和 Weekly Summary <a class="header-anchor" href="#activity-ledger-和-weekly-summary" aria-label="Permalink to “Activity Ledger 和 Weekly Summary”">​</a></h2><p>当 activity logging 开启时，Knowlery 会把轻量的私有 activity receipts 写入 <code>.knowlery/activity/</code>。</p><p>这些 receipts 会驱动：</p><ul><li>Today 的线程摘要和下一步建议。</li><li>This note 的相关上下文。</li><li>Weekly summary 报告，位置在 <code>.knowlery/reports/latest.html</code> 和 <code>.knowlery/reports/weekly/&lt;week-label&gt;.html</code>。</li><li>可选的 daily review request 与结果文件，位置在 <code>.knowlery/requests/</code> 和 <code>.knowlery/reviews/</code>。</li></ul><h2 id="freshness-review" tabindex="-1">Freshness Review <a class="header-anchor" href="#freshness-review" aria-label="Permalink to “Freshness Review”">​</a></h2><p>Freshness Review 是本地、approval-gated 的流程。Knowlery 可以从 <code>entities/</code>、<code>concepts/</code>、<code>comparisons/</code> 和 <code>queries/</code> 收集候选页面，准备 request JSON，并复制 prompt 给你单独运行的 agent。</p><p>导入 result JSON 后，Knowlery 会把合法 findings 转成 suggestions。应用 suggestion 只会 patch scalar frontmatter 字段，例如 <code>retrieval_priority</code>、<code>freshness_status</code>、<code>freshness_reviewed</code>、<code>superseded_by</code> 和 <code>freshness_sidecar</code>。证据和之前的 frontmatter snapshot 会保存在 <code>.knowlery/freshness/notes/</code> sidecars 中，因此已应用的 suggestion 可以恢复。</p><h2 id="knowledge-bundles" tabindex="-1">Knowledge Bundles <a class="header-anchor" href="#knowledge-bundles" aria-label="Permalink to “Knowledge Bundles”">​</a></h2><p>Knowledge bundle 是一个便携的、review 过的知识切片，用 OKF 格式打包，来自某个 vault 的 compiled knowledge。</p><p>在分享侧，导出范围从一个 seed 主题及其 graph-closure 选出，每一项都要经过 approve/flag review gate 和自动 risk scan，随包的 <code>SCHEMA.md</code> 只包含这个 bundle 实际用到的 taxonomy。在接收侧，bundle 安装到 <code>Library/&lt;bundle-id&gt;/</code>，登记在 <code>.knowlery/bundles.json</code> 中，作为只读参考材料存在——直到你用 Fork to my knowledge 把某个页面复制进自己的知识目录。</p><p>已安装的 bundles 会参与检索：bundles 存在期间 <code>KNOWLEDGE.md</code> 会带一个指引块，<code>/ask</code> skill 会把每个相关 bundle 的 <code>agent-index.json</code> 和 vault 自己的 compiled pages 一起纳入检索。</p><h2 id="platform-adapters" tabindex="-1">Platform Adapters <a class="header-anchor" href="#platform-adapters" aria-label="Permalink to “Platform Adapters”">​</a></h2><p>Knowlery 支持两个 agent 平台：</p><table tabindex="0"><thead><tr><th>平台</th><th>配置文件</th><th>Rules 目录</th></tr></thead><tbody><tr><td>Claude Code</td><td><code>.claude/CLAUDE.md</code></td><td><code>.claude/rules/</code></td></tr><tr><td>OpenCode</td><td><code>opencode.json</code></td><td><code>.agents/rules/</code></td></tr></tbody></table><p>切换平台时，Knowlery 会重新生成目标平台配置，并可以迁移之前平台目录中的 rules。</p><h2 id="companion-chat" tabindex="-1">Companion Chat <a class="header-anchor" href="#companion-chat" aria-label="Permalink to “Companion Chat”">​</a></h2><p>Knowlery 可以把 prompt 发给 companion chat UI（如果它可用）：</p><ul><li>Claude Code 场景下用 Claudian。</li><li>OpenCode 场景下用 <code>obsidian-agent-client</code>。</li></ul><p>这样 review prompt 可以留在 vault 里，而不是被丢到另一个 app 中。</p><h2 id="vault-health" tabindex="-1">Vault Health <a class="header-anchor" href="#vault-health" aria-label="Permalink to “Vault Health”">​</a></h2><p>Settings 中的 Diagnostics 会检查两类内容：</p><ul><li><strong>内容结构：</strong> notes 数量、wikilinks 数量、知识页面数量、孤立笔记、损坏 wikilinks、缺失 frontmatter。</li><li><strong>配置完整性：</strong> 预期文件、目录、rules、内置 skills、agent CLI detection 和平台配置。</li></ul>',63)])])}const m=t(r,[["render",c]]);export{b as __pageData,m as default};
